+        let ptr = strstr(hay, c"world".as_ptr());
+
+        assert!(!ptr.is_null());
+        assert_eq!(ptr.offset_from(hay), 6);
+
+        frankenlibc_abi::malloc_abi::free(hay.cast());
+    }
